const raw = $json.body ?? $json;
const legacyBody = raw.body && typeof raw.body === 'object' ? raw.body : {};
const responsesFromLegacy = Array.isArray(legacyBody.body) ? legacyBody.body : [];

const payload = {
  campaign_id: raw.campaign_id ?? legacyBody.campaign_id,
  campaign_name: raw.campaign_name ?? legacyBody.campaign_name ?? '',
  company_name: raw.company_name ?? legacyBody.company_name ?? '',
  client_email: raw.client_email ?? legacyBody.client_email ?? raw.user_email ?? legacyBody.user_email ?? '',
  participants_count: Number(raw.participants_count ?? legacyBody.participants_count ?? raw.total_participants ?? legacyBody.total_participants ?? 0),
  responses_count: Number(raw.responses_count ?? legacyBody.responses_count ?? 0),
  participation_rate: Number(raw.participation_rate ?? legacyBody.participation_rate ?? 0),
  questions: Array.isArray(raw.questions) ? raw.questions : Array.isArray(legacyBody.questions) ? legacyBody.questions : [],
  responses: Array.isArray(raw.responses) ? raw.responses : Array.isArray(legacyBody.responses) ? legacyBody.responses : responsesFromLegacy,
  dimensions: Array.isArray(raw.dimensions) ? raw.dimensions : Array.isArray(legacyBody.dimensions) ? legacyBody.dimensions : []
};

payload.campaign_id = Number(payload.campaign_id);
payload.campaign_name = String(payload.campaign_name || `Campagne ${payload.campaign_id || ''}`).trim();
payload.company_name = String(payload.company_name || 'Entreprise').trim();
payload.client_email = String(process.env.REPORT_RECIPIENT_EMAIL || payload.client_email || '').trim();
payload.responses_count = payload.responses_count || payload.responses.length;
payload.participants_count = payload.participants_count || payload.responses_count;
payload.participation_rate = payload.participation_rate || (payload.participants_count ? Number(((payload.responses_count / payload.participants_count) * 100).toFixed(2)) : 0);

const sendGridFromEmail = process.env.SENDGRID_FROM_EMAIL || process.env.FROM_EMAIL;
const sendGridFromName = process.env.SENDGRID_FROM_NAME || process.env.FROM_NAME;
const driveRootFolderName = process.env.GOOGLE_DRIVE_FOLDER;
const driveShareEmail = process.env.GOOGLE_DRIVE_SHARE_EMAIL;
const missing = [];
if (!payload.campaign_id) missing.push('campaign_id');
if (!payload.responses.length) missing.push('responses');
if (!payload.client_email) missing.push('REPORT_RECIPIENT_EMAIL ou client_email');
if (!process.env.BACKEND_API_URL) missing.push('BACKEND_API_URL');
if (!process.env.API_KEY) missing.push('API_KEY');
if (!process.env.SENDGRID_API_KEY) missing.push('SENDGRID_API_KEY');
if (!sendGridFromEmail) missing.push('SENDGRID_FROM_EMAIL');
if (!sendGridFromName) missing.push('SENDGRID_FROM_NAME');
if (!driveRootFolderName) missing.push('GOOGLE_DRIVE_FOLDER');
if (!driveShareEmail) missing.push('GOOGLE_DRIVE_SHARE_EMAIL');

if (missing.length) {
  throw new Error(`Payload/configuration n8n invalide: ${missing.join(', ')}`);
}

return [{
  json: {
    ...payload,
    report_recipient_email: payload.client_email,
    from_name: sendGridFromName.trim(),
    from_email: sendGridFromEmail,
    reply_to: process.env.SENDGRID_REPLY_TO || process.env.REPLY_TO_EMAIL || sendGridFromEmail,
    drive_root_folder_name: driveRootFolderName.trim(),
    drive_share_email: driveShareEmail.trim(),
    received_at: new Date().toISOString()
  }
}];

const payload = $input.first().json;

function asNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

function isLikert(value) {
  const number = asNumber(value);
  return number !== null && number >= 1 && number <= 5;
}

const questionStats = new Map();
const openAnswers = [];

for (const row of payload.responses) {
  for (const [key, value] of Object.entries(row ?? {})) {
    if (!/^Q\d+$/i.test(key)) continue;
    const rawValue = value == null ? '' : String(value).trim();
    if (!rawValue) continue;

    if (!questionStats.has(key)) {
      questionStats.set(key, { question: key, count: 0, sum: 0, values: {}, average: null });
    }

    const stat = questionStats.get(key);
    if (isLikert(rawValue)) {
      const score = Number(rawValue);
      stat.count += 1;
      stat.sum += score;
      stat.values[score] = (stat.values[score] ?? 0) + 1;
      stat.average = Number((stat.sum / stat.count).toFixed(2));
    } else if (rawValue.length > 2) {
      openAnswers.push({ question: key, answer: rawValue });
    }
  }
}

const quantitative_stats = Array.from(questionStats.values()).sort((left, right) => {
  const leftIndex = Number(left.question.replace(/\D/g, ''));
  const rightIndex = Number(right.question.replace(/\D/g, ''));
  return leftIndex - rightIndex;
});

const aiContext = {
  campaign: {
    campaign_id: payload.campaign_id,
    company_name: payload.company_name,
    campaign_name: payload.campaign_name,
    participants_count: payload.participants_count,
    responses_count: payload.responses_count,
    participation_rate: payload.participation_rate
  },
  questions: payload.questions,
  dimensions: payload.dimensions,
  quantitative_stats,
  open_answers: openAnswers.slice(0, 200),
  responses: payload.responses
};

return [{
  json: {
    ...payload,
    quantitative_stats,
    open_answers: openAnswers,
    ai_context: JSON.stringify(aiContext, null, 2)
  }
}];

const payload = $('Préparer contexte IA').first().json;
const aiRaw = $input.first().json.output || $input.first().json.text || $input.first().json.response || Object.values($input.first().json)[0] || '';

function extractJson(value) {
  if (typeof value === 'object' && value !== null) return value;
  const text = String(value || '').trim();
  try { return JSON.parse(text); } catch {}
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start >= 0 && end > start) {
    try { return JSON.parse(text.slice(start, end + 1)); } catch {}
  }
  return {
    executive_summary: text || 'Analyse indisponible.',
    global_risk_level: 'unknown',
    categories: [],
    recommendations: [],
    hr_actions: [],
    open_answers_summary: ''
  };
}

const analysis = extractJson(aiRaw);
const now = new Date();
const isoDate = now.toISOString().slice(0, 10);

function sanitizeFilePart(value) {
  return String(value || 'Entreprise')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 80) || 'Entreprise';
}

const fileName = `Rapport_RPS_${sanitizeFilePart(payload.company_name)}_${isoDate}.docx`;
const drivePath = `${payload.drive_root_folder_name}/${payload.company_name}/${payload.campaign_name}`;

function escapeXml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

function paragraph(text, style = '') {
  const styleXml = style ? `<w:pPr><w:pStyle w:val="${style}"/></w:pPr>` : '';
  return `<w:p>${styleXml}<w:r><w:t xml:space="preserve">${escapeXml(text)}</w:t></w:r></w:p>`;
}

function list(items) {
  return (items || []).filter(Boolean).map((item) => paragraph(`- ${item}`)).join('');
}

const categories = Array.isArray(analysis.categories) ? analysis.categories : [];
const recommendations = Array.isArray(analysis.recommendations) ? analysis.recommendations : [];
const hrActions = Array.isArray(analysis.hr_actions) ? analysis.hr_actions : [];

let body = '';
body += paragraph('Rapport d’analyse RPS', 'Title');
body += paragraph(`Entreprise : ${payload.company_name}`);
body += paragraph(`Campagne : ${payload.campaign_name}`);
body += paragraph(`Date : ${isoDate}`);
body += paragraph(`Participants : ${payload.participants_count}`);
body += paragraph(`Répondants : ${payload.responses_count}`);
body += paragraph(`Taux de participation : ${payload.participation_rate}%`);
body += paragraph('');
body += paragraph('Résumé exécutif', 'Heading1');
body += paragraph(analysis.executive_summary || 'Résumé non fourni par l’IA.');
body += paragraph(`Niveau de risque global : ${analysis.global_risk_level || 'non renseigné'}`);
body += paragraph('');
body += paragraph('Analyse détaillée par catégorie', 'Heading1');

if (categories.length) {
  for (const category of categories) {
    body += paragraph(category.name || 'Catégorie RPS', 'Heading2');
    if (category.score !== undefined && category.score !== null) body += paragraph(`Score : ${category.score}`);
    if (category.risk_level) body += paragraph(`Niveau de risque : ${category.risk_level}`);
    body += paragraph(category.analysis || 'Analyse non renseignée.');
    if (category.risk_factors?.length) {
      body += paragraph('Facteurs de risque', 'Heading3');
      body += list(category.risk_factors);
    }
    if (category.protective_factors?.length) {
      body += paragraph('Facteurs protecteurs', 'Heading3');
      body += list(category.protective_factors);
    }
    if (category.recommendations?.length) {
      body += paragraph('Recommandations spécifiques', 'Heading3');
      body += list(category.recommendations);
    }
  }
} else {
  body += paragraph('Aucune catégorie structurée n’a été retournée par l’IA.');
}

body += paragraph('');
body += paragraph('Réponses ouvertes', 'Heading1');
body += paragraph(analysis.open_answers_summary || 'Aucune synthèse spécifique des réponses ouvertes.');
body += paragraph('');
body += paragraph('Recommandations RH', 'Heading1');
body += list(recommendations);
body += paragraph('');
body += paragraph('Plan d’action proposé', 'Heading1');
body += list(hrActions);
body += paragraph('');
body += paragraph('Confidentiel – Usage interne uniquement');

const documentXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>${body}<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440"/></w:sectPr></w:body></w:document>`;

const contentTypes = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>`;
const rels = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>`;
const wordRels = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>`;
const styles = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="Title"><w:name w:val="Title"/><w:rPr><w:b/><w:sz w:val="40"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Heading1"><w:name w:val="heading 1"/><w:rPr><w:b/><w:sz w:val="28"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Heading2"><w:name w:val="heading 2"/><w:rPr><w:b/><w:sz w:val="24"/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="Heading3"><w:name w:val="heading 3"/><w:rPr><w:b/><w:sz w:val="21"/></w:rPr></w:style></w:styles>`;
const core = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:dcmitype="http://purl.org/dc/dcmitype/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>${escapeXml(`Rapport RPS - ${payload.company_name}`)}</dc:title><dc:creator>${escapeXml(payload.from_name)}</dc:creator><cp:lastModifiedBy>n8n</cp:lastModifiedBy><dcterms:created xsi:type="dcterms:W3CDTF">${now.toISOString()}</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">${now.toISOString()}</dcterms:modified></cp:coreProperties>`;
const app = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties" xmlns:vt="http://schemas.openxmlformats.org/officeDocument/2006/docPropsVTypes"><Application>n8n</Application></Properties>`;

function crc32(buffer) {
  let table = crc32.table;
  if (!table) {
    table = crc32.table = Array.from({ length: 256 }, (_, n) => {
      let c = n;
      for (let k = 0; k < 8; k++) c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
      return c >>> 0;
    });
  }
  let crc = 0xffffffff;
  for (const byte of buffer) crc = table[(crc ^ byte) & 0xff] ^ (crc >>> 8);
  return (crc ^ 0xffffffff) >>> 0;
}

function dosDateTime(date) {
  const time = (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2);
  const day = date.getDate();
  const month = date.getMonth() + 1;
  const year = Math.max(date.getFullYear() - 1980, 0);
  return { time, date: (year << 9) | (month << 5) | day };
}

function u16(value) { const b = Buffer.alloc(2); b.writeUInt16LE(value); return b; }
function u32(value) { const b = Buffer.alloc(4); b.writeUInt32LE(value >>> 0); return b; }

function zip(files) {
  const localParts = [];
  const centralParts = [];
  let offset = 0;
  const dt = dosDateTime(now);

  for (const file of files) {
    const name = Buffer.from(file.name, 'utf8');
    const data = Buffer.isBuffer(file.data) ? file.data : Buffer.from(file.data, 'utf8');
    const crc = crc32(data);
    const localHeader = Buffer.concat([
      u32(0x04034b50), u16(20), u16(0), u16(0), u16(dt.time), u16(dt.date), u32(crc), u32(data.length), u32(data.length), u16(name.length), u16(0), name
    ]);
    localParts.push(localHeader, data);

    const centralHeader = Buffer.concat([
      u32(0x02014b50), u16(20), u16(20), u16(0), u16(0), u16(dt.time), u16(dt.date), u32(crc), u32(data.length), u32(data.length), u16(name.length), u16(0), u16(0), u16(0), u16(0), u32(0), u32(offset), name
    ]);
    centralParts.push(centralHeader);
    offset += localHeader.length + data.length;
  }

  const centralSize = centralParts.reduce((sum, part) => sum + part.length, 0);
  const end = Buffer.concat([
    u32(0x06054b50), u16(0), u16(0), u16(files.length), u16(files.length), u32(centralSize), u32(offset), u16(0)
  ]);

  return Buffer.concat([...localParts, ...centralParts, end]);
}

const docx = zip([
  { name: '[Content_Types].xml', data: contentTypes },
  { name: '_rels/.rels', data: rels },
  { name: 'word/document.xml', data: documentXml },
  { name: 'word/_rels/document.xml.rels', data: wordRels },
  { name: 'word/styles.xml', data: styles },
  { name: 'docProps/core.xml', data: core },
  { name: 'docProps/app.xml', data: app }
]);

const binary = await this.helpers.prepareBinaryData(
  docx,
  fileName,
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
);

return [{
  json: {
    ...payload,
    ai_analysis: analysis,
    file_name: fileName,
    drive_path: drivePath,
    generated_at: now.toISOString()
  },
  binary: { data: binary }
}];

const report = $('Générer DOCX réel').first();
const campaignFolder = $input.first().json;
return [{
  json: {
    ...report.json,
    drive_folder_id: campaignFolder.id,
    drive_folder_name: campaignFolder.name
  },
  binary: report.binary
}];

const report = $('R\u00e9attacher DOCX').first();
const upload = $('Drive - Upload DOCX').first().json;
const fileId = upload.id || upload.fileId;
const driveUrl = upload.webViewLink || upload.webContentLink || (fileId ? `https://drive.google.com/file/d/${fileId}/view` : '');

if (!driveUrl) {
  throw new Error('Google Drive did not return a usable report link.');
}

if (!process.env.SENDGRID_API_KEY) {
  throw new Error('SENDGRID_API_KEY is required to send email with SendGrid.');
}

const fromEmail = process.env.SENDGRID_FROM_EMAIL || process.env.FROM_EMAIL;
if (!fromEmail) {
  throw new Error('SENDGRID_FROM_EMAIL is required to send email with SendGrid.');
}

const fromName = process.env.SENDGRID_FROM_NAME || process.env.FROM_NAME;
if (!fromName) {
  throw new Error('SENDGRID_FROM_NAME is required to send email with SendGrid.');
}
const replyTo = process.env.SENDGRID_REPLY_TO || process.env.REPLY_TO_EMAIL || fromEmail;
const emailTo = process.env.REPORT_RECIPIENT_EMAIL || report.json.client_email;
const driveShareEmail = process.env.GOOGLE_DRIVE_SHARE_EMAIL || report.json.drive_share_email;
const subject = `Rapport RPS - ${report.json.company_name} - ${report.json.campaign_name}`;
const html = `Bonjour,<br><br>Le rapport RPS pour <strong>${report.json.company_name}</strong> / <strong>${report.json.campaign_name}</strong> est joint a ce message.<br><br>Cordialement,<br>${fromName}`;
const text = [
  'Bonjour,',
  '',
  `Le rapport RPS pour ${report.json.company_name} / ${report.json.campaign_name} est joint a ce message.`,
  '',
  'Cordialement,',
  fromName
].join('\n');

const attachment = report.binary?.data;
if (!attachment?.data) {
  throw new Error('The generated DOCX is missing from n8n binary data.');
}

return [{
  json: {
    ...report.json,
    drive_file_id: fileId,
    drive_web_url: driveUrl,
    email_to: emailTo,
    email_from: fromEmail,
    email_reply_to: replyTo,
    email_from_name: fromName,
    drive_share_email: driveShareEmail,
    sendgrid_report_payload: {
      personalizations: [
        { to: [{ email: emailTo }] }
      ],
      from: { email: fromEmail, name: fromName },
      reply_to: { email: replyTo },
      subject,
      content: [
        { type: 'text/plain', value: text },
        { type: 'text/html', value: html }
      ],
      attachments: [
        {
          content: attachment.data,
          filename: attachment.fileName || report.json.file_name || 'Rapport_RPS.docx',
          type: attachment.mimeType || 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
          disposition: 'attachment'
        }
      ]
    }
  },
  binary: report.binary
}];

const report = $('Préparer email et callback').first().json;
console.log(JSON.stringify({
  event: 'rps_report_completed',
  campaign_id: report.campaign_id,
  company_name: report.company_name,
  campaign_name: report.campaign_name,
  report_path: report.drive_web_url,
  recipient: report.email_to,
  timestamp: new Date().toISOString()
}));
return [{ json: { success: true, campaign_id: report.campaign_id, report_path: report.drive_web_url } }];

if (!process.env.BACKEND_API_URL) throw new Error('BACKEND_API_URL est requis pour les relances.');
if (!process.env.API_KEY) throw new Error('API_KEY est requis pour les relances.');
if (!process.env.SENDGRID_API_KEY) throw new Error('SENDGRID_API_KEY est requis pour les relances.');
if (!(process.env.SENDGRID_FROM_EMAIL || process.env.FROM_EMAIL)) throw new Error('SENDGRID_FROM_EMAIL est requis pour les relances.');
if (!(process.env.SENDGRID_FROM_NAME || process.env.FROM_NAME)) throw new Error('SENDGRID_FROM_NAME est requis pour les relances.');

return [{
  json: {
    minimum_days_since_invitation: Number(process.env.REMINDER_MIN_DAYS || 6),
    max_reminder_count: Number(process.env.REMINDER_MAX_COUNT || 2),
    prepared_at: new Date().toISOString()
  }
}];

const minimumDays = Number(process.env.REMINDER_MIN_DAYS || 6);
const maxReminderCount = Number(process.env.REMINDER_MAX_COUNT || 2);
const now = new Date();
const result = [];

const fromEmail = process.env.SENDGRID_FROM_EMAIL || process.env.FROM_EMAIL;
const fromName = process.env.SENDGRID_FROM_NAME || process.env.FROM_NAME;
const replyTo = process.env.SENDGRID_REPLY_TO || process.env.REPLY_TO_EMAIL || fromEmail;
const reminderSubject = process.env.REMINDER_EMAIL_SUBJECT || 'Sondage RPS - rappel';

function daysSince(value) {
  if (!value) return null;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return Math.floor((now.getTime() - date.getTime()) / (24 * 60 * 60 * 1000));
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function campaignPayloadsFrom(payload) {
  if (!payload) return [];
  if (Array.isArray(payload.campaigns)) return payload.campaigns;
  if (Array.isArray(payload)) {
    const looksLikeCampaigns = payload.every((entry) => entry && Array.isArray(entry.participants));
    return looksLikeCampaigns ? payload : [{ participants: payload }];
  }
  return [payload];
}

for (const item of $input.all()) {
  for (const campaignPayload of campaignPayloadsFrom(item.json)) {
    const participants = Array.isArray(campaignPayload.participants)
      ? campaignPayload.participants
      : Array.isArray(campaignPayload.pending_reminders)
        ? campaignPayload.pending_reminders
        : [];

    for (const participant of participants) {
      const status = String(participant.status || participant.statut || '').toLowerCase();
      const reminderCount = Number(participant.reminder_count || 0);
      const days = daysSince(participant.invitation_sent_at);
      const reminderAlreadyToday = daysSince(participant.reminder_sent_at) === 0;

      if (!participant.email) continue;
      if (!participant.survey_url) continue;
      if (status === 'completed' || status === 'complete') continue;
      if (days === null || days < minimumDays) continue;
      if (reminderCount >= maxReminderCount) continue;
      if (reminderAlreadyToday) continue;

      const participantId = participant.participant_id || participant.id;
      const campaignId = participant.campaign_id || campaignPayload.campaign_id;
      const name = participant.nom || participant.name || participant.full_name || participant.email;
      const firstName = String(name).split(/\s+/)[0] || participant.email;
      const campaignName = participant.campaign_name || campaignPayload.campaign_name || `Campagne ${campaignId || ''}`.trim();
      const html = `Bonjour ${escapeHtml(firstName)},<br><br>Votre participation au sondage RPS est toujours attendue.<br><br>Lien du sondage : <a href="${escapeHtml(participant.survey_url)}">${escapeHtml(participant.survey_url)}</a><br><br>Merci,<br>${escapeHtml(fromName)}`;
      const text = [
        `Bonjour ${firstName},`,
        '',
        'Votre participation au sondage RPS est toujours attendue.',
        '',
        `Lien du sondage : ${participant.survey_url}`,
        '',
        'Merci,',
        fromName
      ].join('\n');

      result.push({
        json: {
          participant_id: participantId,
          campaign_id: campaignId,
          campaign_name: campaignName,
